INSERT INTO `article` VALUES (5067005100558288, 766, 20, 68, '无', '【国务院、中央军委公布实施新修订的《军人抚恤优待条例》】\n\n国务院、中央军委日前公布新修订的《军人抚恤优待条例》（以下简称《条例》），自2024年10月1日起施行。\n\n新修订的《条例》旨在保障国家对军人的抚恤优待，激励军人保卫祖国、建设祖国的献身精神，加强国防和军队现代化建设，让军人成为全 ​', 1263, '2024-08-13', '热门', 'https://weibo.com/5611549371/Os76K2leE', 'https://tvax1.sinaimg.cn/crop.0.0.520.520.180/0067LukPly8h8vg7pyxkzj60eg0eg75502.jpg?KID=imgbed,tva&Expires=1724265598&ssig=FL%2Fr8tIsJe', '国防部发布', 'https://weibo.com/u/5611549371', 0);
