INSERT INTO `article` VALUES (5068997478844236, 765, 155, 105, '无', '【#菲海警船故意冲撞中方海警艇画面公布#】8月19日，菲律宾4410、4411号海警船未经中国政府允许，非法闯入中国南沙群岛仙宾礁邻近海域，中国海警依法对菲船只采取管控措施。菲4410号船无视中方多次严正警告，以不专业、危险方式，故意冲撞中方正常维权执法的21551艇，导致发生擦碰，责任完全在菲方。 ​', 428, '2024-08-19', '热门', 'https://weibo.com/7468777622/OsWWfB6MY', 'https://tvax1.sinaimg.cn/crop.0.0.600.600.180/0089sefcly8h8w5e04zjuj30go0gowhn.jpg?KID=imgbed,tva&Expires=1724265601&ssig=b9bso7Ub8d', '南部战区', 'https://weibo.com/u/7468777622', 0);
