INSERT INTO `article` VALUES (5068686107609663, 231, 14, 29, '无', '【“鹰击-2024”中泰空军联合训练 中方参训部队进行适应性飞行训练】\n\n8月16日，“鹰击-2024”中泰空军联合训练中方参训部队进行首次适应性飞行训练。当天，多架不同型号的中方战机从泰国空军乌隆基地呼啸升空，飞赴预定空域展开针对性训练。\n\n据介绍，抵达乌隆基地后，中方参训部队立即与泰方开展战法 ​', 428, '2024-08-18', '热门', 'https://weibo.com/5611549371/OsOQ2vVCv', 'https://tvax1.sinaimg.cn/crop.0.0.520.520.180/0067LukPly8h8vg7pyxkzj60eg0eg75502.jpg?KID=imgbed,tva&Expires=1724265601&ssig=mxwEJTIBSZ', '国防部发布', 'https://weibo.com/u/5611549371', 0);
