INSERT INTO `article` VALUES (5178557815066490, 0, 0, 0, '无', '在伊犁河公园骑车 双人脚踏车很好玩\n河边的小路宽阔 一路互怼打闹走走停停 \n笑声洒落在平静汹涌着的西北内流河岸边\n\n新疆完全颠覆我的刻板印象\n竟然有河流有绿地有公园 有草地有树林有花\n有繁华闹市车水马龙 虽然感觉周末游客也不算很多\n但是老城区很多维族面孔和俄式建筑让我觉得是在外国\n\n看完日落从 ​', 0, '2025-06-17', '实时', 'https://weibo.com/2023295037/PwXE9lg1A', 'https://tvax4.sinaimg.cn/crop.0.0.1002.1002.180/7899083dly8i1gil663m3j20ru0ru40p.jpg?KID=imgbed,tva&Expires=1750158723&ssig=vk4laSr%2Fhv', '-好梦一声钟鼓里-', 'https://weibo.com/u/2023295037', 0);
