INSERT INTO `article` VALUES (4931461268120265, 872, 508, 466, '无', '#安全你我他#【加强杂草藤蔓治理 确保变压器稳定运行】8月4日，国网沙洋县供电公司高阳供电所“鄂电红马甲”对王集村台区日常巡线工作时，发现王集线烟14变压器存在树枝过长遮挡变压器等可能危及设备供电安全的情况，立即开展杂草藤蔓等消缺工作，有效预防电力设备故障，提高供电可靠性。（谢祖会） ​', 277, '2023-08-05', '热门', 'https://weibo.com/5506825031/NdcrYy4s1', 'https://tvax3.sinaimg.cn/crop.86.153.383.383.180/0060G4Kzly8h8vi6dfmm7j30fg0j60t9.jpg?KID=imgbed,tva&Expires=1691408985&ssig=yWSqcy%2FbWB', '国网湖北电力', 'https://weibo.com/u/5506825031', 0);
