INSERT INTO `article` VALUES (4932000450349972, 0, 0, 1, '无', '#每日一习话#【#唯有创新才能抢占先机#】习近平：创新决定未来。建设世界科技强国，不是一片坦途，唯有创新才能抢占先机。\n\n这段话出自2019年2月20日习近平总书记在会见探月工程嫦娥四号任务参研参试人员代表时的讲话。\n\n科技强才能产业强、经济强、国家强，这是人类社会发展的客观规律，也是国家间综 ​', 1698, '2023-08-07', '热门', 'https://weibo.com/1867571077/NdqtD1t2I', 'https://tvax1.sinaimg.cn/crop.0.0.1080.1080.180/0022o8y9ly8h8vg74fpp7j60u00u0abf02.jpg?KID=imgbed,tva&Expires=1691408985&ssig=Q6VWXnoTry', '听中国', 'https://weibo.com/u/1867571077', 0);
