INSERT INTO `article` VALUES (4932047401127858, 436, 0, 0, '广东', '免费医疗不可取\n不少人好奇，为什么中国不适用免费医疗呢？\n对此，国家医保局表示，当前社会和经济发展的条件下，医保筹资水平还不高，基金支撑能力还不足。\n谈及未来，医保局认为，个人承担一定的医疗卫生支出责任有必要，实行免费医疗不利于医疗保障制度长期稳定实施。\n其实，大家不必羡慕所谓的免费 ​', 633, '2023-08-07', '热门', 'https://weibo.com/2374245313/NdrHm4Jpg', 'https://tvax1.sinaimg.cn/crop.0.0.959.959.180/8d841bc1ly8hfxzpa6fhcj20qn0qnq5z.jpg?KID=imgbed,tva&Expires=1691408985&ssig=b9oPmOEJhs', '龙头股阿强', 'https://weibo.com/u/2374245313', 0);
