INSERT INTO `article` VALUES (4932042896974021, 91, 27, 17, '北京', '楼下公园里，每天都有不少坐着轮椅的老人在晒太阳，他们花钱请的保姆或者护工们，则在尽情地跳舞玩耍。他们也许还算幸运的，恐怕有一大部分退休老人，每月的退休金还不够请一个保姆的。未来若干年，每年将有2000多万人步入退休行列，未富先老的中国人，正在快步走进超老龄化社会[允悲]  ​', 305, '2023-08-07', '同城', 'https://weibo.com/1358776365/NdrA5tggd', 'https://tva4.sinaimg.cn/crop.0.0.996.996.180/50fd482djw8f3r04g5kbrj20ro0rptau.jpg?KID=imgbed,tva&Expires=1691409376&ssig=rEVDesKoil', '老徐时评', 'https://weibo.com/u/1358776365', 0);
