INSERT INTO `comments` VALUES (5178091987275341, '2025-06-17', 7, '山东', '是行李箱门打开没法关闭，用共享单车当路障提醒过往行人，不然骑车过去的容易看不到，人视线正常看过去是平的，直接头撞上去就危险了，然后用这个挡一下提醒人员，不过，这种车上不放几个锥形桶啥的路障吗[允悲]用共享单车影响多不好', '聊城之声', 'm', '山东', 'https://tvax3.sinaimg.cn/crop.0.0.512.512.180/9d392443ly8g8u4tmjqtdj20e80e8weo.jpg?KID=imgbed,tva&Expires=1750158800&ssig=%2BsnCiC9KAV');
