INSERT INTO `comments` VALUES (5169575395858463, '2025-06-07', 6, '浙江', '杨超越，己卯日生在未月，己卯是山林之兔，灵动自由，不拘一格。杨超越这格局也可说道说道，又是劫财透干，不以为敌，却为用，反败为胜之格。得此命造，如同统御八方人力，自然来财。因此又被称之为分财之神。杨超越在情缘上不够清明，有花开并蒂的趋势。', '洋芋酪酪', 'm', '四川', 'https://tvax1.sinaimg.cn/crop.0.0.500.500.180/007Wkz5sly8i1uyycfnw1j30dw0dwaap.jpg?KID=imgbed,tva&Expires=1750158801&ssig=85%2FjFoPFEC');
