INSERT INTO `comments` VALUES (4930005891815175, '2024-08-02', 70, '安徽', '我快一年没进过影院看电影了，看了《封神》，直接发疯。电影里的一切都在传递着“我是被真诚对待的观众”。酣畅淋漓，意犹未尽，我不理解黑子的黑点从何而来，电影也许不是最完美的，但他是中国神话电影的一大步。东方的神话史诗，它配得上这个称号。', 'Vicky晴儿呐', 'f', '安徽', 'https://tvax4.sinaimg.cn/crop.0.3.1073.1073.180/005PtCtQly8h97ixc0n23j30tt0u0juf.jpg?KID=imgbed,tva&Expires=1691409398&ssig=ktLXldh1pA');
