INSERT INTO `comments` VALUES (4932042896974021, '2024-08-07', 3, '江苏', '自己掏干退休金请保姆一般舍不得。大部分是子女出一部分（视能力大小和配偶态度决定出资额度），也有经济实力强的全出；出钱的基本出发点是：只要不住我这。能出钱的还算孝顺的，既不愿自己照顾又不肯花钱的多的是。当下至往后，老了就是灾难，不敢老。', '雨巷斜柳樱桃红', 'm', '江苏', 'https://tva1.sinaimg.cn/crop.0.0.180.180.180/702f0e2bjw1e8qgp5bmzyj2050050aa8.jpg?KID=imgbed,tva&Expires=1691409403&ssig=j5LwmiD1VA');
