INSERT INTO `comments` VALUES (4929660473049646, '2024-08-01', 5, '俄罗斯', '想出国不一定要很多钱啊。欧美很贵，但是我们俄罗斯普通专业一年学费就两万多人民币。还能申请国家公费，只要你成绩好。免学费，免住宿费，每个月给几百块钱补贴（肯定不够生活费但是聊胜于无）。踏马的我们俄罗斯留学生也是留学生啊，不止欧美吞金兽是留学生啊！！！[微笑][微笑][微笑]', '麻歌鸡', 'm', '其他', 'https://tvax3.sinaimg.cn/crop.0.0.700.700.180/006o5qx2ly8h2e3o6f32fj30jg0jgae4.jpg?KID=imgbed,tva&Expires=1691409420&ssig=3Us4opA%2FwC');
